            sourceUrl4: 'https://www.idnfinancials.com/id/news/65419/dbs-ihsg-bisa-tutup-2026-di-8-000-namun-tergantung-tiga-faktor-ini',
            sourceSnippet4: 'DBS: IHSG bisa tutup 2026 di 8.000, tergantung tiga faktor — IDN Financials'
